.darma-loader-darma-custom-713 {
  color: var(--loader-color, #f59e0b);
width: 40px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(currentColor 0 0);
background:
var(--c) 0 0,
var(--c) 0 100%,
var(--c) 50% 0,  
 var(--c) 50% 100%,
var(--c) 100% 0,
var(--c) 100% 100%;
background-size: 8px 50%;
animation: darma-loader-darma-custom-713-l8-0 2s infinite;
position: relative;
overflow: hidden;
}
.darma-loader-darma-custom-713:before {
content: "";
position: absolute;
width: 8px;
height: 8px;
border-radius: 50%;
background: currentColor;
top: calc(50% - 4px);
left: -8px;
animation: inherit;
animation-name: darma-loader-darma-custom-713-l8-1;
}
@keyframes darma-loader-darma-custom-713-l8-0 {
16.67% {background-size:8px 30%, 8px 30%, 8px 50%, 8px 50%, 8px 50%, 8px 50%}
33.33% {background-size:8px 30%, 8px 30%, 8px 30%, 8px 30%, 8px 50%, 8px 50%}
50% {background-size:8px 30%, 8px 30%, 8px 30%, 8px 30%, 8px 50%, 8px 50%}
66.67% {background-size:8px 50%, 8px 50%, 8px 30%, 8px 30%, 8px 50%, 8px 50%}
83.33% {background-size:8px 50%, 8px 50%, 8px 50%, 8px 50%, 8px 50%, 8px 50%}
}
@keyframes darma-loader-darma-custom-713-l8-1 {
20% {left:0px}
40%,100% {left:calc(50% - 4px)}
}

